from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson import ObjectId
from datetime import datetime
import os

app = Flask(__name__)

MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
DB_NAME = os.getenv("MONGO_DB", "cms_db")

client = MongoClient(MONGO_URI)
db = client[DB_NAME]
users_col = db["users"]
documents_col = db["documents"]


def serialize_doc(doc):
    if not doc:
        return None
    doc = dict(doc)
    doc["_id"] = str(doc["_id"])
    if "user_id" in doc and isinstance(doc["user_id"], ObjectId):
        doc["user_id"] = str(doc["user_id"])
    if "created_at" in doc and hasattr(doc["created_at"], "isoformat"):
        doc["created_at"] = doc["created_at"].isoformat()
    if "updated_at" in doc and hasattr(doc["updated_at"], "isoformat"):
        doc["updated_at"] = doc["updated_at"].isoformat()
    return doc


def to_object_id(value):
    try:
        return ObjectId(value)
    except Exception:
        return None


@app.route("/health", methods=["GET"])
def health():
    try:
        client.admin.command("ping")
        return jsonify({"status": "ok"}), 200
    except Exception as e:
        return jsonify({"status": "error", "detail": str(e)}), 500


@app.route("/users", methods=["POST"])
def create_user():
    payload = request.get_json(force=True, silent=True) or {}
    required = ["username", "email"]
    missing = [k for k in required if not payload.get(k)]
    if missing:
        return jsonify({"error": "missing_fields", "fields": missing}), 400

    now = datetime.utcnow()
    user = {
        "username": payload["username"],
        "email": payload["email"],
        "display_name": payload.get("display_name", ""),
        "bio": payload.get("bio", ""),
        "role": payload.get("role", "author"),
        "metadata": payload.get("metadata", {}),
        "created_at": now,
        "updated_at": now,
    }

    existing = users_col.find_one({"$or": [{"username": user["username"]}, {"email": user["email"]}]})
    if existing:
        return jsonify({"error": "user_exists"}), 409

    result = users_col.insert_one(user)
    user["_id"] = str(result.inserted_id)
    user["created_at"] = user["created_at"].isoformat()
    user["updated_at"] = user["updated_at"].isoformat()
    return jsonify(user), 201


@app.route("/users/<user_id>", methods=["GET"])
def get_user(user_id):
    oid = to_object_id(user_id)
    if not oid:
        return jsonify({"error": "invalid_user_id"}), 400
    user = users_col.find_one({"_id": oid})
    if not user:
        return jsonify({"error": "not_found"}), 404
    return jsonify(serialize_doc(user)), 200


@app.route("/users/<user_id>", methods=["PUT"])
def update_user(user_id):
    oid = to_object_id(user_id)
    if not oid:
        return jsonify({"error": "invalid_user_id"}), 400

    payload = request.get_json(force=True, silent=True) or {}
    update_fields = {}
    for field in ["username", "email", "display_name", "bio", "role", "metadata"]:
        if field in payload:
            update_fields[field] = payload[field]

    if not update_fields:
        return jsonify({"error": "no_fields_to_update"}), 400

    update_fields["updated_at"] = datetime.utcnow()
    result = users_col.update_one({"_id": oid}, {"$set": update_fields})
    if result.matched_count == 0:
        return jsonify({"error": "not_found"}), 404

    user = users_col.find_one({"_id": oid})
    return jsonify(serialize_doc(user)), 200


@app.route("/documents", methods=["POST"])
def create_document():
    payload = request.get_json(force=True, silent=True) or {}
    required = ["title", "content", "user_id"]
    missing = [k for k in required if not payload.get(k)]
    if missing:
        return jsonify({"error": "missing_fields", "fields": missing}), 400

    user_oid = to_object_id(payload["user_id"])
    if not user_oid or not users_col.find_one({"_id": user_oid}):
        return jsonify({"error": "invalid_or_missing_user"}), 400

    now = datetime.utcnow()
    doc = {
        "title": payload["title"],
        "content": payload["content"],
        "user_id": user_oid,
        "tags": payload.get("tags", []),
        "status": payload.get("status", "draft"),
        "metadata": payload.get("metadata", {}),
        "created_at": now,
        "updated_at": now,
    }
    result = documents_col.insert_one(doc)
    doc["_id"] = str(result.inserted_id)
    doc["user_id"] = str(doc["user_id"])
    doc["created_at"] = doc["created_at"].isoformat()
    doc["updated_at"] = doc["updated_at"].isoformat()
    return jsonify(doc), 201


