@app.route("/documents", methods=["GET"])
def query_documents():
    filters = {}

    user_id = request.args.get("user_id")
    status = request.args.get("status")
    tag = request.args.get("tag")
    text = request.args.get("q")
    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)

    if user_id:
        oid = to_object_id(user_id)
        if not oid:
            return jsonify({"error": "invalid_user_id"}), 400
        filters["user_id"] = oid

    if status:
        filters["status"] = status

    if tag:
        filters["tags"] = tag

    if text:
        filters["$text"] = {"$search": text}

    cursor = documents_col.find(filters).sort("created_at", -1).skip(skip).limit(limit)
    items = [serialize_doc(doc) for doc in cursor]
    total = documents_col.count_documents(filters)
    return jsonify({"items": items, "total": total, "limit": limit, "skip": skip}), 200


@app.route("/documents/search", methods=["POST"])
def advanced_document_search():
    payload = request.get_json(force=True, silent=True) or {}
    match = payload.get("match", {})
    sort = payload.get("sort", {"created_at": -1})
    limit = min(int(payload.get("limit", 20)), 100)
    skip = max(int(payload.get("skip", 0)), 0)

    if "user_id" in match:
        oid = to_object_id(match["user_id"])
        if not oid:
            return jsonify({"error": "invalid_user_id"}), 400
        match["user_id"] = oid

    pipeline = [
        {"$match": match},
        {"$sort": sort},
        {"$skip": skip},
        {"$limit": limit},
    ]
    items = [serialize_doc(doc) for doc in documents_col.aggregate(pipeline)]
    return jsonify({"items": items, "pipeline": pipeline}), 200


@app.route("/analytics/document-stats", methods=["GET"])
def document_stats():
    pipeline = [
        {
            "$group": {
                "_id": "$status",
                "count": {"$sum": 1},
                "avg_content_length": {"$avg": {"$strLenCP": "$content"}},
            }
        },
        {"$sort": {"count": -1}},
    ]
    results = list(documents_col.aggregate(pipeline))
    for r in results:
        if "_id" in r:
            r["status"] = r.pop("_id")
    return jsonify({"items": results}), 200


@app.route("/analytics/user-content", methods=["GET"])
def user_content_analytics():
    pipeline = [
        {
            "$lookup": {
                "from": "users",
                "localField": "user_id",
                "foreignField": "_id",
                "as": "user",
            }
        },
        {"$unwind": "$user"},
        {
            "$group": {
                "_id": "$user._id",
                "username": {"$first": "$user.username"},
                "email": {"$first": "$user.email"},
                "document_count": {"$sum": 1},
                "draft_count": {"$sum": {"$cond": [{"$eq": ["$status", "draft"]}, 1, 0]}},
                "published_count": {"$sum": {"$cond": [{"$eq": ["$status", "published"]}, 1, 0]}},
            }
        },
        {"$sort": {"document_count": -1}},
    ]

    items = list(documents_col.aggregate(pipeline))
    for item in items:
        item["_id"] = str(item["_id"])
    return jsonify({"items": items}), 200


@app.route("/documents/<doc_id>", methods=["DELETE"])
def delete_document(doc_id):
    oid = to_object_id(doc_id)
    if not oid:
        return jsonify({"error": "invalid_document_id"}), 400
    result = documents_col.delete_one({"_id": oid})
    if result.deleted_count == 0:
        return jsonify({"error": "not_found"}), 404
    return jsonify({"deleted": True}), 200


@app.route("/users/<user_id>/documents", methods=["GET"])
def user_documents(user_id):
    oid = to_object_id(user_id)
    if not oid:
        return jsonify({"error": "invalid_user_id"}), 400
    if not users_col.find_one({"_id": oid}):
        return jsonify({"error": "not_found"}), 404
    cursor = documents_col.find({"user_id": oid}).sort("created_at", -1)
    items = [serialize_doc(doc) for doc in cursor]
    return jsonify({"items": items, "total": len(items)}), 200


